@@ -0,0 +1,400 @@
+//! Comprehensive benchmark comparing different matmul implementations
+//!
+//! Tests:
+//! 1. CBLAS (CPU, Float32)
+//! 2. vDSP (CPU, Float32)
+//! 3. Metal BF16 (GPU, native BF16)
+//!
+//! For the critical size: [1, 5120] × [5120, 5120] (Qwen2.5-32B hidden size)
+
+const std = @import("std");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+const objc = @import("inference/metal/objc.zig");
+
+const shader_source = @embedFile("inference/metal/matmul_bf16.metal");
+
+/// Helper functions for BF16 conversion
+inline fn bf16ToF32(bf16: BF16) f32 {
+    const u32_val: u32 = @as(u32, bf16) << 16;
+    return @bitCast(u32_val);
+}
+
+inline fn f32ToBF16(f32_val: f32) BF16 {
+    const u32_val: u32 = @bitCast(f32_val);
+    return @truncate(u32_val >> 16);
+}
+
+// CBLAS bindings
+const cblas = struct {
+    const CblasRowMajor: c_int = 101;
+    const CblasNoTrans: c_int = 111;
+
+    extern "c" fn cblas_sgemm(
+        order: c_int,
+        transA: c_int,
+        transB: c_int,
+        m: c_int,
+        n: c_int,
+        k: c_int,
+        alpha: f32,
+        a: [*]const f32,
+        lda: c_int,
+        b: [*]const f32,
+        ldb: c_int,
+        beta: f32,
+        c: [*]f32,
+        ldc: c_int,
+    ) void;
+};
+
+// vDSP bindings
+const vdsp = struct {
+    const vDSP_Length = c_ulong;
+    const vDSP_Stride = c_long;
+
+    extern "c" fn vDSP_mmul(
+        a: [*]const f32,
+        ia: vDSP_Stride,
+        b: [*]const f32,
+        ib: vDSP_Stride,
+        c: [*]f32,
+        ic: vDSP_Stride,
+        m: vDSP_Length,
+        n: vDSP_Length,
+        p: vDSP_Length,
+    ) void;
+};
+
+fn benchmarkCBLAS(
+    allocator: std.mem.Allocator,
+    a: []const BF16,
+    b: []const BF16,
+    c_out: []BF16,
+    m: u32,
+    k: u32,
+    n: u32,
+    iterations: u32,
+) !i128 {
+    // Allocate Float32 buffers
+    const a_f32 = try allocator.alloc(f32, m * k);
+    defer allocator.free(a_f32);
+    const b_f32 = try allocator.alloc(f32, k * n);
+    defer allocator.free(b_f32);
+    const c_f32 = try allocator.alloc(f32, m * n);
+    defer allocator.free(c_f32);
+
+    // Convert BF16 to Float32
+    for (a, 0..) |val, i| a_f32[i] = bf16ToF32(val);
+    for (b, 0..) |val, i| b_f32[i] = bf16ToF32(val);
+
+    var total_time: i128 = 0;
+
+    var i: u32 = 0;
+    while (i < iterations) : (i += 1) {
+        const start = std.time.nanoTimestamp();
+
+        cblas.cblas_sgemm(
+            cblas.CblasRowMajor,
+            cblas.CblasNoTrans,
+            cblas.CblasNoTrans,
+            @intCast(m),
+            @intCast(n),
+            @intCast(k),
+            1.0,
+            a_f32.ptr,
+            @intCast(k),
+            b_f32.ptr,
+            @intCast(n),
+            0.0,
+            c_f32.ptr,
+            @intCast(n),
+        );
+
+        const end = std.time.nanoTimestamp();
+        total_time += end - start;
+    }
+
+    // Convert back for verification
+    for (c_f32, 0..) |val, idx| c_out[idx] = f32ToBF16(val);
+
+    return total_time;
+}
+
+fn benchmarkVDSP(
+    allocator: std.mem.Allocator,
+    a: []const BF16,
+    b: []const BF16,
+    c_out: []BF16,
+    m: u32,
+    k: u32,
+    n: u32,
+    iterations: u32,
+) !i128 {
+    // Allocate Float32 buffers
+    const a_f32 = try allocator.alloc(f32, m * k);
+    defer allocator.free(a_f32);
+    const b_f32 = try allocator.alloc(f32, k * n);
+    defer allocator.free(b_f32);
+    const c_f32 = try allocator.alloc(f32, m * n);
+    defer allocator.free(c_f32);
+
+    // Convert BF16 to Float32
+    for (a, 0..) |val, i| a_f32[i] = bf16ToF32(val);
+    for (b, 0..) |val, i| b_f32[i] = bf16ToF32(val);
+
+    var total_time: i128 = 0;
+
+    var i: u32 = 0;
+    while (i < iterations) : (i += 1) {
+        const start = std.time.nanoTimestamp();
+
+        vdsp.vDSP_mmul(
+            a_f32.ptr,
+            1,
+            b_f32.ptr,
+            1,
+            c_f32.ptr,
+            1,
+            @intCast(m),
+            @intCast(n),
+            @intCast(k),
+        );
+
+        const end = std.time.nanoTimestamp();
+        total_time += end - start;
+    }
+
+    // Convert back for verification
+    for (c_f32, 0..) |val, idx| c_out[idx] = f32ToBF16(val);
+
+    return total_time;
+}
+
+fn benchmarkMetalBF16(
+    device: objc.MTLDevice,
+    queue: objc.MTLCommandQueue,
+    pipeline: objc.MTLComputePipelineState,
+    a: []const BF16,
+    b: []const BF16,
+    c_out: []BF16,
+    _: u32, // m (unused - always 1 for this benchmark)
+    k: u32,
+    n: u32,
+    iterations: u32,
+) !i128 {
+    // Create Metal buffers (reused across iterations)
+    const a_buffer = objc.deviceNewBufferWithBytes(
+        device,
+        @ptrCast(a.ptr),
+        a.len * @sizeOf(BF16),
+        objc.MTLResourceStorageModeShared,
+    ) orelse return error.BufferCreationFailed;
+
+    const b_buffer = objc.deviceNewBufferWithBytes(
+        device,
+        @ptrCast(b.ptr),
+        b.len * @sizeOf(BF16),
+        objc.MTLResourceStorageModeShared,
+    ) orelse return error.BufferCreationFailed;
+
+    const c_buffer = objc.deviceNewBuffer(
+        device,
+        c_out.len * @sizeOf(BF16),
+        objc.MTLResourceStorageModeShared,
+    ) orelse return error.BufferCreationFailed;
+
+    var total_time: i128 = 0;
+
+    var i: u32 = 0;
+    while (i < iterations) : (i += 1) {
+        const start = std.time.nanoTimestamp();
+
+        // Create command buffer
+        const cmd_buffer = objc.commandQueueCommandBuffer(queue) orelse {
+            return error.CommandBufferCreationFailed;
+        };
+
+        // Create compute encoder
+        const encoder = objc.commandBufferComputeEncoder(cmd_buffer) orelse {
+            return error.EncoderCreationFailed;
+        };
+
+        // Set pipeline and buffers
+        objc.encoderSetPipelineState(encoder, pipeline);
+        objc.encoderSetBuffer(encoder, a_buffer, 0, 0);
+        objc.encoderSetBuffer(encoder, b_buffer, 0, 1);
+        objc.encoderSetBuffer(encoder, c_buffer, 0, 2);
+        objc.encoderSetBytes(encoder, &k, @sizeOf(u32), 3);
+        objc.encoderSetBytes(encoder, &n, @sizeOf(u32), 4);
+
+        // Dispatch
+        const threads_per_grid = objc.MTLSize{ .width = n, .height = 1, .depth = 1 };
+        const threads_per_group = objc.MTLSize{ .width = @min(n, 256), .height = 1, .depth = 1 };
+        objc.encoderDispatchThreads(encoder, threads_per_grid, threads_per_group);
+
+        objc.encoderEndEncoding(encoder);
+
+        // Execute
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+
+        const end = std.time.nanoTimestamp();
+        total_time += end - start;
+    }
+
+    // Copy result back
+    const c_ptr = objc.bufferContents(c_buffer);
+    @memcpy(c_out, @as([*]BF16, @ptrCast(@alignCast(c_ptr)))[0..c_out.len]);
+
+    return total_time;
+}
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    std.debug.print("\n╔══════════════════════════════════════════════════════╗\n", .{});
+    std.debug.print("║  Matrix Multiplication Performance Comparison       ║\n", .{});
+    std.debug.print("║  CBLAS vs vDSP vs Metal BF16                        ║\n", .{});
+    std.debug.print("╚══════════════════════════════════════════════════════╝\n\n", .{});
+
+    // Test size: Qwen2.5-32B hidden size projection
+    const m: u32 = 1;
+    const k: u32 = 5120;
+    const n: u32 = 5120;
+    const iterations: u32 = 20;
+
+    std.debug.print("Matrix size: [{}, {}] × [{}, {}] = [{}, {}]\n", .{ m, k, k, n, m, n });
+    std.debug.print("FLOPs per matmul: {} million\n", .{2 * m * k * n / 1_000_000});
+    std.debug.print("Iterations: {}\n\n", .{iterations});
+
+    // Allocate test data
+    const a = try allocator.alloc(BF16, m * k);
+    defer allocator.free(a);
+    const b = try allocator.alloc(BF16, k * n);
+    defer allocator.free(b);
+    const c_cblas = try allocator.alloc(BF16, m * n);
+    defer allocator.free(c_cblas);
+    const c_vdsp = try allocator.alloc(BF16, m * n);
+    defer allocator.free(c_vdsp);
+    const c_metal = try allocator.alloc(BF16, m * n);
+    defer allocator.free(c_metal);
+
+    // Fill with test data (1.0 in BF16 = 0x3F80)
+    @memset(a, 0x3F80);
+    @memset(b, 0x3F80);
+
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Benchmark 1: CBLAS (CPU, Float32)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    const cblas_time = try benchmarkCBLAS(allocator, a, b, c_cblas, m, k, n, iterations);
+    const cblas_avg_ms = @as(f64, @floatFromInt(cblas_time)) / @as(f64, @floatFromInt(iterations)) / 1_000_000.0;
+    const cblas_gflops = (2.0 * @as(f64, @floatFromInt(m * k * n))) / (cblas_avg_ms / 1000.0) / 1_000_000_000.0;
+
+    std.debug.print("Total time: {d:.2}ms\n", .{@as(f64, @floatFromInt(cblas_time)) / 1_000_000.0});
+    std.debug.print("Average per iteration: {d:.2}ms\n", .{cblas_avg_ms});
+    std.debug.print("Performance: {d:.2} GFLOPS\n\n", .{cblas_gflops});
+
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Benchmark 2: vDSP (CPU, Float32)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    const vdsp_time = try benchmarkVDSP(allocator, a, b, c_vdsp, m, k, n, iterations);
+    const vdsp_avg_ms = @as(f64, @floatFromInt(vdsp_time)) / @as(f64, @floatFromInt(iterations)) / 1_000_000.0;
+    const vdsp_gflops = (2.0 * @as(f64, @floatFromInt(m * k * n))) / (vdsp_avg_ms / 1000.0) / 1_000_000_000.0;
+
+    std.debug.print("Total time: {d:.2}ms\n", .{@as(f64, @floatFromInt(vdsp_time)) / 1_000_000.0});
+    std.debug.print("Average per iteration: {d:.2}ms\n", .{vdsp_avg_ms});
+    std.debug.print("Performance: {d:.2} GFLOPS\n\n", .{vdsp_gflops});
+
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Benchmark 3: Metal BF16 (GPU, native BF16)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    // Setup Metal
+    const device = objc.createSystemDefaultDevice() orelse return error.MetalDeviceNotFound;
+    const queue = objc.deviceNewCommandQueue(device) orelse return error.CommandQueueFailed;
+
+    const ns_source = objc.createNSStringLong(shader_source) orelse return error.StringCreationFailed;
+    defer objc.release(ns_source);
+
+    var err: ?objc.NSError = null;
+    const library = objc.deviceNewLibraryWithSource(device, ns_source, null, &err);
+    if (library == null) {
+        if (err) |e| {
+            const desc = objc.errorGetDescription(e);
+            std.debug.print("❌ Shader compilation failed: {s}\n", .{desc});
+        }
+        return error.ShaderCompilationFailed;
+    }
+
+    const function_name_str = objc.createNSString("matmul_bf16_m1") orelse return error.StringCreationFailed;
+    defer objc.release(function_name_str);
+
+    const function = objc.libraryNewFunction(library.?, function_name_str) orelse {
+        return error.FunctionNotFound;
+    };
+
+    const pipeline = objc.deviceNewComputePipelineState(device, function, &err);
+    if (pipeline == null) {
+        if (err) |e| {
+            const desc = objc.errorGetDescription(e);
+            std.debug.print("❌ Pipeline creation failed: {s}\n", .{desc});
+        }
+        return error.PipelineCreationFailed;
+    }
+
+    const metal_time = try benchmarkMetalBF16(device, queue, pipeline.?, a, b, c_metal, m, k, n, iterations);
+    const metal_avg_ms = @as(f64, @floatFromInt(metal_time)) / @as(f64, @floatFromInt(iterations)) / 1_000_000.0;
+    const metal_gflops = (2.0 * @as(f64, @floatFromInt(m * k * n))) / (metal_avg_ms / 1000.0) / 1_000_000_000.0;
+
+    std.debug.print("Total time: {d:.2}ms\n", .{@as(f64, @floatFromInt(metal_time)) / 1_000_000.0});
+    std.debug.print("Average per iteration: {d:.2}ms\n", .{metal_avg_ms});
+    std.debug.print("Performance: {d:.2} GFLOPS\n\n", .{metal_gflops});
+
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("COMPARISON\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    std.debug.print("CBLAS:      {d:.2}ms  ({d:.2} GFLOPS)  [baseline]\n", .{ cblas_avg_ms, cblas_gflops });
+    std.debug.print("vDSP:       {d:.2}ms  ({d:.2} GFLOPS)  [{d:.1}x {s}]\n", .{
+        vdsp_avg_ms,
+        vdsp_gflops,
+        cblas_avg_ms / vdsp_avg_ms,
+        if (vdsp_avg_ms < cblas_avg_ms) "faster" else "slower",
+    });
+    std.debug.print("Metal BF16: {d:.2}ms  ({d:.2} GFLOPS)  [{d:.1}x {s}]\n\n", .{
+        metal_avg_ms,
+        metal_gflops,
+        cblas_avg_ms / metal_avg_ms,
+        if (metal_avg_ms < cblas_avg_ms) "faster" else "slower",
+    });
+
+    // Verify correctness
+    const expected: BF16 = @intCast(k); // Each output element should be sum of k 1.0s = k
+    const expected_f32 = bf16ToF32(expected);
+
+    std.debug.print("═══════════════════════════════════════════════════════\n", .{});
+    std.debug.print("CORRECTNESS CHECK\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════\n\n", .{});
+
+    std.debug.print("Expected output: {d:.1} (each element)\n", .{expected_f32});
+    std.debug.print("CBLAS output[0]:  {d:.1}\n", .{bf16ToF32(c_cblas[0])});
+    std.debug.print("vDSP output[0]:   {d:.1}\n", .{bf16ToF32(c_vdsp[0])});
+    std.debug.print("Metal output[0]:  {d:.1}\n\n", .{bf16ToF32(c_metal[0])});
+
+    const winner = blk: {
+        if (metal_avg_ms < cblas_avg_ms and metal_avg_ms < vdsp_avg_ms) {
+            break :blk "Metal BF16 (GPU)";
+        } else if (cblas_avg_ms < vdsp_avg_ms) {
+            break :blk "CBLAS (CPU)";
+        } else {
+            break :blk "vDSP (CPU)";
+        }
+    };
+
+    std.debug.print("🏆 Winner: {s}\n", .{winner});
+    std.debug.print("\n", .{});
+}

