+//! Metal compute shader for BF16 matrix multiplication
+//! Optimized for M=1 (single row) which is common in LLM inference
+//!
+//! C[1, N] = A[1, K] × B[K, N]
+//!
+//! This keeps everything in BF16 on GPU for maximum performance.
+
+#include <metal_stdlib>
+using namespace metal;
+
+// BF16 matrix multiply kernel for M=1 (single row output)
+// A: [1, K] - single row input
+// B: [K, N] - weight matrix
+// C: [1, N] - single row output
+//
+// Each thread computes one element of the output
+kernel void matmul_bf16_m1(
+    device const bfloat *A [[buffer(0)]],      // [1, K]
+    device const bfloat *B [[buffer(1)]],      // [K, N]
+    device bfloat *C [[buffer(2)]],            // [1, N]
+    constant uint &K [[buffer(3)]],
+    constant uint &N [[buffer(4)]],
+    uint n [[thread_position_in_grid]]
+) {
+    if (n >= N) return;
+
+    // Compute C[0, n] = sum(A[0, k] * B[k, n] for k in 0..K)
+    float sum = 0.0f;
+
+    // Unroll by 4 for better performance
+    uint k = 0;
+    for (; k + 4 <= K; k += 4) {
+        sum += float(A[k + 0]) * float(B[(k + 0) * N + n]);
+        sum += float(A[k + 1]) * float(B[(k + 1) * N + n]);
+        sum += float(A[k + 2]) * float(B[(k + 2) * N + n]);
+        sum += float(A[k + 3]) * float(B[(k + 3) * N + n]);
+    }
+
+    // Handle remaining elements
+    for (; k < K; k++) {
+        sum += float(A[k]) * float(B[k * N + n]);
+    }
+
+    C[n] = bfloat(sum);
+}
+
+// General BF16 matrix multiply kernel for arbitrary M
+// A: [M, K]
+// B: [K, N]
+// C: [M, N]
+//
+// Each thread computes one element of the output
+kernel void matmul_bf16_general(
+    device const bfloat *A [[buffer(0)]],      // [M, K]
+    device const bfloat *B [[buffer(1)]],      // [K, N]
+    device bfloat *C [[buffer(2)]],            // [M, N]
+    constant uint &M [[buffer(3)]],
+    constant uint &K [[buffer(4)]],
+    constant uint &N [[buffer(5)]],
+    uint2 pos [[thread_position_in_grid]]
+) {
+    const uint m = pos.y;
+    const uint n = pos.x;
+
+    if (m >= M || n >= N) return;
+
+    // Compute C[m, n] = sum(A[m, k] * B[k, n] for k in 0..K)
+    float sum = 0.0f;
+
+    const uint a_offset = m * K;
+
+    // Unroll by 4 for better performance
+    uint k = 0;
+    for (; k + 4 <= K; k += 4) {
+        sum += float(A[a_offset + k + 0]) * float(B[(k + 0) * N + n]);
+        sum += float(A[a_offset + k + 1]) * float(B[(k + 1) * N + n]);
+        sum += float(A[a_offset + k + 2]) * float(B[(k + 2) * N + n]);
+        sum += float(A[a_offset + k + 3]) * float(B[(k + 3) * N + n]);
+    }
+
+    // Handle remaining elements
+    for (; k < K; k++) {
+        sum += float(A[a_offset + k]) * float(B[k * N + n]);
+    }
+
+    C[m * N + n] = bfloat(sum);
+}
+
+// Optimized version using threadgroup memory for better cache utilization
+// This is faster for larger matrices
+kernel void matmul_bf16_tiled(
+    device const bfloat *A [[buffer(0)]],      // [M, K]
+    device const bfloat *B [[buffer(1)]],      // [K, N]
+    device bfloat *C [[buffer(2)]],            // [M, N]
+    constant uint &M [[buffer(3)]],
+    constant uint &K [[buffer(4)]],
+    constant uint &N [[buffer(5)]],
+    uint2 gid [[thread_position_in_grid]],
+    uint2 tid [[thread_position_in_threadgroup]],
+    uint2 tgsize [[threads_per_threadgroup]]
+) {
+    const uint TILE_SIZE = 32;
+
+    threadgroup bfloat A_tile[TILE_SIZE][TILE_SIZE];
+    threadgroup bfloat B_tile[TILE_SIZE][TILE_SIZE];
+
+    const uint row = gid.y;
+    const uint col = gid.x;
+
+    if (row >= M || col >= N) return;
+
+    float sum = 0.0f;
+
+    // Loop over tiles
+    for (uint t = 0; t < (K + TILE_SIZE - 1) / TILE_SIZE; t++) {
+        // Load tile of A
+        const uint a_col = t * TILE_SIZE + tid.x;
+        if (row < M && a_col < K) {
+            A_tile[tid.y][tid.x] = A[row * K + a_col];
+        } else {
+            A_tile[tid.y][tid.x] = bfloat(0.0f);
+        }
+
+        // Load tile of B
+        const uint b_row = t * TILE_SIZE + tid.y;
+        if (b_row < K && col < N) {
+            B_tile[tid.y][tid.x] = B[b_row * N + col];
+        } else {
+            B_tile[tid.y][tid.x] = bfloat(0.0f);
+        }
+
+        threadgroup_barrier(mem_flags::mem_threadgroup);
+
+        // Compute partial sum
+        for (uint k = 0; k < TILE_SIZE; k++) {
+            sum += float(A_tile[tid.y][k]) * float(B_tile[k][tid.x]);
+        }
+
+        threadgroup_barrier(mem_flags::mem_threadgroup);
+    }
+
+    C[row * N + col] = bfloat(sum);
+}

